import React, { useState, useEffect } from "react";
import { Plus, Trash2, Camera, Printer, Share2, Download, ClipboardList, ChevronLeft, RefreshCw} from "lucide-react";
import SignaturePad from "./SignaturePad";
import { shareReportPdf } from "../lib/shareReportPdf";

const CORP_LOGO = "data:image/jpeg;base64,";

const DEPT_LOGOS = {
  JPTS: "data:image/svg+xml;base64,",
  JGM: "data:image/svg+xml;base64,",
  JA: "data:image/svg+xml;base64,",
  JI: "data:image/svg+xml;base64,",
  JDG: "data:image/png;base64,",
  JDM: "data:image/jpeg;base64,",
  GRA: "data:image/svg+xml;base64,",
  AS: "data:image/jpeg;base64,",
  P21: "data:image/png;base64,"
};

function deptLogo(code) {
  const map = {
    JAF1: "JA", JAF2: "JA", JAF3: "JA",
    JIF1: "JI", JIF2: "JI", JIF5: "JI",
    JDG: "JDG", JDM: "JDM", GRA: "GRA", AS: "AS", P21: "P21", JPTS: "JPTS", JGM: "JGM",
  };
  const key = map[code];
  return key ? DEPT_LOGOS[key] : CORP_LOGO;
}


function compressImage(file, maxWidth) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        let width = img.width;
        let height = img.height;
        if (width > maxWidth) {
          height = Math.round(height * (maxWidth / width));
          width = maxWidth;
        }
        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL("image/jpeg", 0.6));
      };
      img.onerror = () => reject(new Error("Could not read image"));
      img.src = e.target.result;
    };
    reader.onerror = () => reject(new Error("Could not read file"));
    reader.readAsDataURL(file);
  });
}

const BRAND = {
  yellow: "#F0B429",
  orange: "#E8622C",
  red: "#C1272D",
  green: "#1E7A46",
  blue: "#1B3C74",
  bg: "#F4F2ED",
};

const FORM_CODE = "JG-HSE-FRM-020-01";
const STORAGE_KEY = "ht_reports_index";

const DEPARTMENTS = [
  { code: "JAF1", name: "JA Factory-1" },
  { code: "JAF2", name: "JA Factory-2" },
  { code: "JAF3", name: "JA Factory-3" },
  { code: "JDG", name: "JDG" },
  { code: "JIF1", name: "JI Factory 1" },
  { code: "JIF2", name: "JI Factory 2" },
  { code: "JIF5", name: "JI Factory 5" },
  { code: "JDM", name: "JDM" },
  { code: "GRA", name: "Graphics" },
  { code: "AS", name: "AS" },
  { code: "P21", name: "PROTO21" },
  { code: "JPTS", name: "Joseph Project and Traffic Sign" },
  { code: "JGM", name: "Joseph General Maintenance" },
  { code: "PROJ_JA", name: "JA" },
  { code: "PROJ_GROUP", name: "Joseph Group" },
];


const CHECK_ITEMS = [
  { key: "HT1", label: "Non-slippery handles/grip" },
  { key: "HT2", label: "Damaged handle/grip" },
  { key: "HT3", label: "Locks on place" },
  { key: "HT4", label: "Sharp tools are guarded" },
  { key: "HT5", label: "Loose fittings" },
  { key: "HT6", label: "Self modification with design" },
  { key: "HT7", label: "Safety measures on place" },
  { key: "HT8", label: "Properly maintained" },
];

const RESULT_OPTIONS = ["OK", "NO", "REP", "ILM", "RET"];

const RESULT_COLORS = {
  OK: { bg: "#EAF3DE", text: "#27500A" },
  NO: { bg: "#F1EFE8", text: "#5F5E5A" },
  REP: { bg: "#FAEEDA", text: "#854F0B" },
  ILM: { bg: "#FCEBEB", text: "#A32D2D" },
  RET: { bg: "#E6F1FB", text: "#0C447C" },
};

function todayStr() {
  const d = new Date();
  const dd = String(d.getDate()).padStart(2, "0");
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const yyyy = d.getFullYear();
  return dd + "/" + mm + "/" + yyyy;
}

function monthStr() {
  return new Date().toLocaleDateString("en-GB", { month: "long" });
}

function blankItem(seq, deptCode) {
  return {
    localId: Math.random().toString(36).slice(2),
    equipmentId: deptCode + "-HT-" + String(seq).padStart(3, "0"),
    type: "",
    results: {},
    remarks: "",
  };
}

export default function HandToolsInspection({ initialDepartment, initialReport, initialScreen, initialProjectName, initialProjectNo } = {}) {
  const [screen, setScreen] = useState(initialScreen || "form");
  const editSeed = initialReport && initialScreen === "form" ? initialReport : null;
  const [department, setDepartment] = useState((editSeed && editSeed.department) || initialDepartment || DEPARTMENTS[0].code);
  const [projectName, setProjectName] = useState(initialProjectName || "");
  const [projectNo, setProjectNo] = useState(initialProjectNo || "");
  const [inspector, setInspector] = useState((editSeed && editSeed.inspector) || "");
  const [signature, setSignature] = useState((editSeed && editSeed.signature) || "");
  const [designation, setDesignation] = useState((editSeed && editSeed.designation) || "HSE Officer");
  const [date, setDate] = useState((editSeed && editSeed.date) || todayStr());
  const [serialNo, setSerialNo] = useState((editSeed && editSeed.serialNo) || "");
  const [photos, setPhotos] = useState((editSeed && editSeed.photos) || []);
  const [items, setItems] = useState((editSeed && editSeed.items) || [blankItem(1, DEPARTMENTS[0].code)]);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [savedReport, setSavedReport] = useState(initialReport || null);
  const [register, setRegister] = useState([]);
  const [loadingRegister, setLoadingRegister] = useState(false);

  function deptName(code) {
    const d = DEPARTMENTS.find((x) => x.code === code);
    return d ? d.name : code;
  }

  function addItem() {
    setItems((prev) => [...prev, blankItem(prev.length + 1, department)]);
  }

  function removeItem(localId) {
    setItems((prev) => prev.filter((it) => it.localId !== localId));
  }

  function updateItem(localId, field, value) {
    setItems((prev) => prev.map((it) => (it.localId === localId ? { ...it, [field]: value } : it)));
  }

  function updateResult(localId, code, value) {
    setItems((prev) => prev.map((it) => (
      it.localId === localId ? { ...it, results: { ...it.results, [code]: value } } : it
    )));
  }

  function itemStatus(it) {
    const vals = Object.values(it.results);
    if (vals.length === 0) return "Pending";
    if (vals.every((v) => v === "OK")) return "Pass";
    return "Attention";
  }

  async function handleAddPhoto(e) {
    const files = Array.from(e.target.files || []).slice(0, 2 - photos.length);
    for (const f of files) {
      try {
        const dataUrl = await compressImage(f, 1000);
        setPhotos((prev) => (prev.length < 2 ? [...prev, dataUrl] : prev));
      } catch (err) {
        // skip unreadable file
      }
    }
    e.target.value = "";
  }

  function removePhoto(idx) {
    setPhotos((prev) => prev.filter((_, i) => i !== idx));
  }

  async function handleSubmit() {
    if ((department === "PROJ_JA" || department === "PROJ_GROUP") && !projectName.trim()) {
      setError("Enter the project name.");
      return;
    }
    if (!serialNo.trim()) {
      setError("Enter the report serial number.");
      return;
    }
    if (items.length === 0) {
      setError("Add at least one equipment item.");
      return;
    }
    setSaving(true);
    setError("");
    try {
      const report = {
        serialNo: serialNo.trim(),
        formCode: FORM_CODE,
        department,
        departmentName: (department === "PROJ_JA" || department === "PROJ_GROUP") ? (deptName(department) + " \u2014 " + projectName.trim() + (projectNo.trim() ? " (" + projectNo.trim() + ")" : "")) : deptName(department),
        inspector,
        signature,
        designation,
        date,
        month: monthStr(),
        items,
        photos,
        submittedAt: new Date().toISOString(),
      };
      const reportKey = "ht_report_" + report.serialNo;
      const saveResult = await window.storage.set(reportKey, JSON.stringify(report), true);
      if (!saveResult) throw new Error("save failed");
      let indexList = [];
      try {
        const idxRes = await window.storage.get(STORAGE_KEY, true);
        if (idxRes) indexList = JSON.parse(idxRes.value);
      } catch (e) {
        indexList = [];
      }
      let okCount = 0;
      let totalCount = 0;
      items.forEach((it) => {
        Object.values(it.results || {}).forEach((v) => {
          if (v) {
            totalCount += 1;
            if (v === "OK") okCount += 1;
          }
        });
      });
      indexList = indexList.filter((x) => x.serialNo !== report.serialNo);
      indexList.unshift({
        serialNo: report.serialNo,
        departmentName: report.departmentName,
        department: report.department,
        inspector: report.inspector,
        date: report.date,
        itemCount: items.length,
        okCount,
        totalCount,
        submittedAt: report.submittedAt,
      });
      const indexResult = await window.storage.set(STORAGE_KEY, JSON.stringify(indexList), true);
      if (!indexResult) throw new Error("index save failed");
      setSavedReport(report);
      setScreen("preview");
    } catch (e) {
      setError("Could not save the report. Check your connection and try again.");
    } finally {
      setSaving(false);
    }
  }

  async function loadRegister() {
    setLoadingRegister(true);
    try {
      const res = await window.storage.get(STORAGE_KEY, true);
      setRegister(res ? JSON.parse(res.value) : []);
    } catch (e) {
      setRegister([]);
    } finally {
      setLoadingRegister(false);
    }
  }

  function goToRegister() {
    setScreen("register");
    loadRegister();
  }

  // Jumping straight into a module's register (e.g. from the Registers menu)
  // still needs its data loaded once on mount.
  useEffect(() => {
    if (initialScreen === "register") loadRegister();
  }, []);

  function startNewReport() {
    setSerialNo("");
    setItems([blankItem(1, department)]);
    setSavedReport(null);
    setError("");
    setScreen("form");
  }

  function exportCsv(report) {
    const headers = ["SL#", "ID#", "Type", ...CHECK_ITEMS.map((c) => c.key), "Remarks"];
    const rows = report.items.map((it, i) => [
      i + 1,
      it.equipmentId,
      it.type,
      ...CHECK_ITEMS.map((c) => it.results[c.key] || ""),
      it.remarks,
    ]);
    const csv = [headers, ...rows].map((r) => r.map((v) => '"' + String(v).replace(/"/g, '""') + '"').join(",")).join("\n");
    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "HandTools_" + report.serialNo + ".csv";
    a.click();
    URL.revokeObjectURL(url);
  }

  const inputStyle = {
    width: "100%", fontSize: 13, padding: "10px 12px", border: "1px solid #d8d5cc",
    borderRadius: 8, marginTop: 4, boxSizing: "border-box", background: "#fff",
  };
  const labelStyle = { fontSize: 11.5, color: "#8a8778", fontWeight: 500 };
  const sectionTitle = { fontSize: 13, fontWeight: 500, color: "#5b594e", margin: "18px 0 8px" };
  const buttonPrimary = {
    width: "100%", padding: "13px 0", background: BRAND.blue, color: "#fff", border: "none",
    borderRadius: 10, fontSize: 14.5, fontWeight: 500, cursor: "pointer",
  };
  const buttonGhost = {
    padding: "9px 14px", background: "transparent", color: BRAND.blue, border: "1px solid " + BRAND.blue,
    borderRadius: 8, fontSize: 12.5, cursor: "pointer", display: "flex", alignItems: "center", gap: 6,
  };

  return (
    <div style={{
      minHeight: 600, fontFamily: "-apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif",
      background: BRAND.bg, padding: "18px 12px 40px",
    }} className="app-shell">
      <style>{`
        @media print {
          .no-print { display: none !important; }
          .app-shell { background: #fff !important; padding: 0 !important; min-height: 0 !important; }
          .app-inner { max-width: none !important; margin: 0 !important; }
          .print-report { box-shadow: none !important; border-radius: 0 !important; }
        }
      `}</style>
      <div style={{ maxWidth: 460, margin: "0 auto" }} className="app-inner">

        <div className="no-print" style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            {screen !== "form" && (
              <ChevronLeft size={18} color={BRAND.blue} style={{ cursor: "pointer" }} onClick={() => setScreen("form")} />
            )}
            <img src={CORP_LOGO} alt="Joseph Group" style={{ height: 30, width: "auto" }} />
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button
              style={buttonGhost}
              aria-label="Refresh"
              onClick={() => (screen === "register" ? loadRegister() : window.location.reload())}
            >
              <RefreshCw size={14} />
            </button>
            <button style={buttonGhost} onClick={goToRegister}>
              <ClipboardList size={14} /> Register
            </button>
          </div>
        </div>

        {screen === "form" && (
          <div>
            <div style={{ background: "#fff", borderRadius: 14, padding: "14px 16px", marginBottom: 4 }}>
              <div style={{ fontSize: 15, fontWeight: 500, color: BRAND.blue }}>Hand tools inspection</div>
              <div style={{ fontSize: 11.5, color: "#8a8778", marginTop: 2 }}>Form {FORM_CODE}</div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 12 }}>
                <div>
                  <div style={labelStyle}>Department</div>
                  <select style={inputStyle} value={department} onChange={(e) => setDepartment(e.target.value)}>
                    {DEPARTMENTS.map((d) => <option key={d.code} value={d.code}>{d.name}</option>)}
                  </select>
                  {(department === "PROJ_JA" || department === "PROJ_GROUP") && (
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginTop: 6 }}>
                      <input style={{ ...inputStyle, marginTop: 0 }} placeholder="Project name" value={projectName} onChange={(e) => setProjectName(e.target.value)} />
                      <input style={{ ...inputStyle, marginTop: 0 }} placeholder="Project no." value={projectNo} onChange={(e) => setProjectNo(e.target.value)} />
                    </div>
                  )}
                </div>
                <div>
                  <div style={labelStyle}>Date</div>
                  <input style={inputStyle} value={date} onChange={(e) => setDate(e.target.value)} placeholder="DD/MM/YYYY" />
                </div>
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 8 }}>
                <div>
                  <div style={labelStyle}>Inspector</div>
                  <input style={inputStyle} value={inspector} onChange={(e) => setInspector(e.target.value)} placeholder="Inspector name" />
                </div>
                <div>
                  <div style={labelStyle}>Designation</div>
                  <input style={inputStyle} value={designation} onChange={(e) => setDesignation(e.target.value)} />
                </div>
              </div>

              <SignaturePad label="Inspector Signature" personName={inspector} value={signature} onChange={setSignature} />

              <div style={{ marginTop: 8 }}>
                <div style={labelStyle}>Report / serial no.</div>
                <input style={inputStyle} value={serialNo} onChange={(e) => setSerialNo(e.target.value)} placeholder="e.g. HT-2026-0001" />
              </div>
            </div>

            <div style={sectionTitle}>Equipment checked ({items.length})</div>

            {items.map((it) => (
              <div key={it.localId} style={{ background: "#fff", borderRadius: 14, padding: "12px 14px", marginBottom: 10 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                  <input
                    style={{ ...inputStyle, marginTop: 0, fontWeight: 500, width: "auto", flex: 1 }}
                    value={it.equipmentId}
                    onChange={(e) => updateItem(it.localId, "equipmentId", e.target.value)}
                  />
                  <div style={{
                    marginLeft: 8, fontSize: 10.5, padding: "3px 8px", borderRadius: 6, whiteSpace: "nowrap",
                    background: itemStatus(it) === "Pass" ? "#EAF3DE" : itemStatus(it) === "Attention" ? "#FCEBEB" : "#F1EFE8",
                    color: itemStatus(it) === "Pass" ? "#27500A" : itemStatus(it) === "Attention" ? "#A32D2D" : "#5F5E5A",
                  }}>
                    {itemStatus(it)}
                  </div>
                  <Trash2 size={16} color="#A32D2D" style={{ marginLeft: 8, cursor: "pointer", flexShrink: 0 }} onClick={() => removeItem(it.localId)} />
                </div>
                <input
                  style={inputStyle}
                  placeholder="Type (e.g. Spanner, Hammer, Pliers, Cutter)"
                  value={it.type}
                  onChange={(e) => updateItem(it.localId, "type", e.target.value)}
                />
                <div style={{ marginTop: 8, display: "flex", flexDirection: "column", gap: 6 }}>
                  {CHECK_ITEMS.map((c) => (
                    <div key={c.key} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ flex: 1, fontSize: 11.5, color: "#2c2c2a" }}>{c.key} &middot; {c.label}</div>
                      <select
                        style={{
                          fontSize: 11.5, padding: "5px 6px", borderRadius: 6, border: "1px solid #d8d5cc",
                          background: it.results[c.key] ? RESULT_COLORS[it.results[c.key]].bg : "#fff",
                          color: it.results[c.key] ? RESULT_COLORS[it.results[c.key]].text : "#8a8778",
                          fontWeight: 500,
                        }}
                        value={it.results[c.key] || ""}
                        onChange={(e) => updateResult(it.localId, c.key, e.target.value)}
                      >
                        <option value="">--</option>
                        {RESULT_OPTIONS.map((o) => <option key={o} value={o}>{o}</option>)}
                      </select>
                    </div>
                  ))}
                </div>
                <input
                  style={{ ...inputStyle, marginTop: 8 }}
                  placeholder="Remarks (optional)"
                  value={it.remarks}
                  onChange={(e) => updateItem(it.localId, "remarks", e.target.value)}
                />
              </div>
            ))}

            <button
              onClick={addItem}
              style={{
                width: "100%", padding: "11px 0", background: "#fff", border: "1px dashed #c9c6ba",
                borderRadius: 10, fontSize: 13, color: BRAND.blue, display: "flex", alignItems: "center",
                justifyContent: "center", gap: 6, cursor: "pointer", marginBottom: 16,
              }}
            >
              <Plus size={15} /> Add another item
            </button>

            <div style={{ background: "#fff", borderRadius: 14, padding: "14px 16px", marginBottom: 10 }}>
              <div style={{ fontSize: 12.5, fontWeight: 500, color: BRAND.blue, marginBottom: 2 }}>Photos (optional)</div>
              <div style={{ fontSize: 11, color: "#8a8778", marginBottom: 8 }}>Attach up to 2 photos if required</div>
              <div style={{ display: "flex", gap: 8 }}>
                {photos.map((p, i) => (
                  <div key={i} style={{ position: "relative" }}>
                    <img src={p} alt={"Photo " + (i + 1)} style={{ width: 90, height: 90, objectFit: "cover", borderRadius: 8, border: "1px solid #e5e2d8" }} />
                    <button onClick={() => removePhoto(i)} style={{ position: "absolute", top: -6, right: -6, width: 20, height: 20, borderRadius: "50%", background: BRAND.red, color: "#fff", border: "none", fontSize: 11, cursor: "pointer", lineHeight: "20px", padding: 0 }}>&times;</button>
                  </div>
                ))}
                {photos.length < 2 && (
                  <label style={{ width: 90, height: 90, border: "1px dashed #b3b0a3", borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24, color: "#8a8778", cursor: "pointer" }}>
                    +
                    <input type="file" accept="image/*" multiple style={{ display: "none" }} onChange={handleAddPhoto} />
                  </label>
                )}
              </div>
            </div>

            {error && <div style={{ color: BRAND.red, fontSize: 12.5, marginBottom: 10 }}>{error}</div>}

            <button style={buttonPrimary} onClick={handleSubmit} disabled={saving}>
              {saving ? "Submitting..." : "Submit inspection"}
            </button>
          </div>
        )}

        {screen === "preview" && savedReport && (
          <div>
            <div className="no-print" style={{ display: "flex", gap: 8, marginBottom: 10 }}>
              <button style={buttonGhost} onClick={() => window.print()}><Printer size={14} /> Print/Save</button>
              <button style={buttonGhost} onClick={() => shareReportPdf({ filename: (savedReport.serialNo || "report") + ".pdf", title: savedReport.serialNo || "HSE Report" })}><Share2 size={14} /> Share</button>
              <button style={buttonGhost} onClick={() => exportCsv(savedReport)}><Download size={14} /> CSV</button>
            </div>

            <div className="print-report" style={{ background: "#fff", borderRadius: 12, padding: 14, fontSize: 10, overflowX: "auto" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10, borderBottom: "2px solid #2c2c2a", paddingBottom: 6, marginBottom: 6 }}>
                {savedReport.department && savedReport.department.startsWith("PROJ_") ? (
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <img src={CORP_LOGO} alt="Joseph Group" style={{ height: 26, maxWidth: 90, objectFit: "contain" }} />
                    <img src={DEPT_LOGOS.JA} alt="JA" style={{ height: 26, maxWidth: 90, objectFit: "contain" }} />
                  </div>
                ) : (
                  <img src={deptLogo(savedReport.department)} alt={savedReport.departmentName} style={{ height: 30, maxWidth: 110, objectFit: "contain" }} />
                )}
                <div style={{ fontSize: 13, fontWeight: 500, textDecoration: "underline" }}>Hand tools inspection</div>
                <div style={{ marginLeft: "auto", fontSize: 9.5, color: "#5b594e" }}>{savedReport.formCode}</div>
              </div>

              <table style={{ width: "100%", borderCollapse: "collapse", marginBottom: 4 }}>
                <tbody>
                  <tr>
                    <td style={{ border: "1px solid #ddd", padding: "3px 6px", fontWeight: 500 }}>Legend: hand tools</td>
                    <td style={{ border: "1px solid #ddd", padding: "3px 6px", fontWeight: 500 }}>
                      Dept: {savedReport.departmentName} &nbsp;|&nbsp; Month: {savedReport.month} &nbsp;|&nbsp; Date: {savedReport.date} &nbsp;|&nbsp; Report No: {savedReport.serialNo}
                    </td>
                  </tr>
                  <tr>
                    <td colSpan={2} style={{ border: "1px solid #ddd", padding: "3px 6px", color: "#5b594e" }}>
                      OK = all in good condition, NO = does not match, REP = item needs repair/replacement, ILM = item lost or missing, RET = returned to store
                    </td>
                  </tr>
                </tbody>
              </table>

              <table style={{ width: "100%", borderCollapse: "collapse", marginBottom: 4 }}>
                <tbody>
                  <tr>
                    <td style={{ border: "1px solid #ddd", padding: "3px 6px", fontWeight: 500 }}>Type: hand tools</td>
                    <td style={{ border: "1px solid #ddd", padding: "3px 6px" }}>Inspector: {savedReport.inspector}</td>
                    <td style={{ border: "1px solid #ddd", padding: "3px 6px" }}>Designation: {savedReport.designation}</td>
                  </tr>
                </tbody>
              </table>

              <table style={{ width: "100%", borderCollapse: "collapse", textAlign: "center" }}>
                <thead>
                  <tr style={{ fontWeight: 500 }}>
                    <td style={{ border: "1px solid #ddd", padding: 3 }}>SL#</td>
                    <td style={{ border: "1px solid #ddd", padding: 3 }}>ID#</td>
                    <td style={{ border: "1px solid #ddd", padding: 3 }}>Type</td>
                    {CHECK_ITEMS.map((c) => (
                      <td key={c.key} style={{ border: "1px solid #ddd", padding: 3 }}>{c.key}</td>
                    ))}
                    <td style={{ border: "1px solid #ddd", padding: 3 }}>Remarks</td>
                  </tr>
                </thead>
                <tbody>
                  {savedReport.items.map((it, i) => (
                    <tr key={it.localId}>
                      <td style={{ border: "1px solid #ddd", padding: 3 }}>{i + 1}</td>
                      <td style={{ border: "1px solid #ddd", padding: 3 }}>{it.equipmentId}</td>
                      <td style={{ border: "1px solid #ddd", padding: 3 }}>{it.type}</td>
                      {CHECK_ITEMS.map((c) => (
                        <td key={c.key} style={{ border: "1px solid #ddd", padding: 3 }}>{it.results[c.key] || "-"}</td>
                      ))}
                      <td style={{ border: "1px solid #ddd", padding: 3 }}>{it.remarks || "-"}</td>
                    </tr>
                  ))}
                </tbody>
              </table>

              {savedReport.photos && savedReport.photos.length > 0 && (
                <div style={{ marginTop: 10 }}>
                  <div style={{ fontWeight: 500, marginBottom: 4 }}>Photos</div>
                  <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    {savedReport.photos.map((p, i) => (
                      <img key={i} src={p} alt={"Photo " + (i + 1)} style={{ width: 160, maxHeight: 160, objectFit: "contain", border: "1px solid #ddd" }} />
                    ))}
                  </div>
                </div>
              )}

              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginTop: 28, fontSize: 9.5, color: "#5b594e" }}>
                <div style={{ textAlign: "left" }}>
                  <div>Inspector name: {savedReport.inspector}</div>
                  <div style={{ marginTop: 2 }}>Designation: {savedReport.designation}</div>
                </div>
                <div style={{ textAlign: "right" }}>
                  {savedReport.signature ? (
                    <img src={savedReport.signature} alt="Signature" style={{ height: 40, marginLeft: "auto", display: "block" }} />
                  ) : (
                    <div style={{ borderBottom: "1px solid #999", width: 140, height: 28, marginLeft: "auto" }}></div>
                  )}
                  <div style={{ marginTop: 2 }}>Signature</div>
                </div>
              </div>
            </div>

            <button className="no-print" style={{ ...buttonPrimary, marginTop: 14 }} onClick={startNewReport}>
              Start new inspection
            </button>
          </div>
        )}

        {screen === "register" && (
          <div>
            <div style={{ fontSize: 15, fontWeight: 500, color: BRAND.blue, marginBottom: 10 }}>Hand tools register</div>
            {loadingRegister && <div style={{ fontSize: 13, color: "#8a8778" }}>Loading...</div>}
            {!loadingRegister && register.length === 0 && (
              <div style={{ fontSize: 13, color: "#8a8778", background: "#fff", borderRadius: 12, padding: 16 }}>
                No inspections submitted yet.
              </div>
            )}
            {!loadingRegister && register.map((r) => (
              <div key={r.serialNo + r.submittedAt} style={{ background: "#fff", borderRadius: 12, padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", justifyContent: "space-between" }}>
                  <div style={{ fontSize: 13, fontWeight: 500, color: "#2c2c2a" }}>{r.serialNo}</div>
                  <div style={{ fontSize: 11.5, color: "#8a8778" }}>{r.date}</div>
                </div>
                <div style={{ fontSize: 11.5, color: "#8a8778", marginTop: 2 }}>
                  {r.departmentName} &middot; {r.inspector} &middot; {r.itemCount} items
                </div>
                <button
                  style={{ ...buttonGhost, marginTop: 8, fontSize: 11.5, padding: "6px 10px" }}
                  onClick={async () => {
                    try {
                      const res = await window.storage.get("ht_report_" + r.serialNo, true);
                      if (res) {
                        setSavedReport(JSON.parse(res.value));
                        setScreen("preview");
                      }
                    } catch (e) {
                      setRegister((prev) => prev);
                    }
                  }}
                >
                  View / print
                </button>
              </div>
            ))}
          </div>
        )}

      </div>
    </div>
  );
}
